// 黑车1
(maindata, torrent) => {
  const categoryList = ["不删"];
  const ruleData = [
    { down: 80, up: 60 },
    { down: 70, up: 45 },
    { down: 60, up: 35 },
    { down: 50, up: 25 },
    { down: 40, up: 20 },
    { down: 20, up: 8 },
    { down: 15, up: 5 },
    { down: 10, up: 2 }
  ];
  const { state, upspeed, category, dlspeed } = torrent.originProp;
  if (categoryList.indexOf(category) !== -1) {
    return false;
  }
  for (const rule of ruleData) {
    if (
      state == "downloading" &&
      dlspeed >= util.calSize(rule.down, "MiB") &&
      upspeed <= util.calSize(rule.up, "MiB")
    ) {
      return true;
    }
  }
  return false;
};
